// TEST SKELETON: internal/contract/executor/executor_multi_turn_test.go
func TestContractExecutor_ExecuteMultiTurn_CircuitBreaker(t *testing.T) {
    exec := NewContractExecutor()
    provider := &failingToolProvider{} // Returns tool calls that always fail
    tr := tool.NewRegistry()
    tr.Register(&alwaysFailingTool{}, nil)
    exec.SetProvider(provider)
    exec.SetToolRegistry(tr)

    contract := &types.AgentContract{
        ContractID: "circuit-test",
        InputSchema: &types.InputSchema{Fields: []types.FieldDef{{Name: "x", Type: types.FieldTypeString}}},
        OutputSchema: &types.OutputSchema{Fields: []types.FieldDef{{Name: "out", Type: types.FieldTypeString}}},
    }
    exec.RegisterContract(contract)

    // 5 consecutive tool errors should trigger circuit breaker
    _, err := exec.Execute("circuit-test", map[string]any{"x": "y"})
    if err == nil {
        t.Fatal("Expected circuit breaker error after 5 failures")
    }
}

